# Concrete shape implementations
from shapes import IShape, IRenderable, ShapeBase, ShapeType, Point

class Circle(ShapeBase, IShape, IRenderable):
    center: Point
    radius: float

    def __init__(self, x: float, y: float, r: float):
        super().__init__(ShapeType.CIRCLE)
        self.center = Point(x, y)
        self.radius = r

    @override
    def describe(self) -> str:
        return f"Circle at ({self.center.x}, {self.center.y}) with radius {self.radius}"

    @override
    def get_type_name(self) -> str:
        return "circle"

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def render(self) -> str:
        return f"[O] r={self.radius}"

class Rectangle(ShapeBase, IShape, IRenderable):
    top_left: Point
    width: float
    height: float

    def __init__(self, x: float, y: float, w: float, h: float):
        super().__init__(ShapeType.RECTANGLE)
        self.top_left = Point(x, y)
        self.width = w
        self.height = h

    @override
    def describe(self) -> str:
        return f"Rectangle at ({self.top_left.x}, {self.top_left.y}): {self.width}x{self.height}"

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def render(self) -> str:
        return f"[_] {self.width}x{self.height}"

