# Shape utilities and operations
from shapes import IShape, ShapeBase, ShapeType, Point
from concrete_shapes import Circle, Rectangle

def calculate_total_area(shapes: list[ShapeBase]) -> float:
    total: float = 0.0
    for shape in shapes:
        # Check if it's a Circle
        if isinstance(shape, Circle):
            c: Circle = shape
            total = total + c.area()
        elif isinstance(shape, Rectangle):
            r: Rectangle = shape
            total = total + r.area()
    return total

def filter_by_type(shapes: list[ShapeBase], t: ShapeType) -> list[ShapeBase]:
    result: list[ShapeBase] = []
    for shape in shapes:
        if shape.type == t:
            result.append(shape)
    return result

def create_shape_factory(type_name: str, x: float, y: float) -> ShapeBase:
    if type_name == "circle":
        return Circle(x, y, 5.0)
    elif type_name == "rectangle":
        return Rectangle(x, y, 10.0, 20.0)
    else:
        return Circle(x, y, 1.0)

class ShapeCollection:
    _shapes: list[ShapeBase]

    def __init__(self):
        self._shapes = []

    def add(self, shape: ShapeBase) -> None:
        self._shapes.append(shape)

    def get_count(self) -> int:
        return len(self._shapes)

    def get_all(self) -> list[ShapeBase]:
        return self._shapes

    def find_by_type(self, t: ShapeType) -> list[ShapeBase]:
        return filter_by_type(self._shapes, t)
